const requestId = 'req-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);
const sessionId = $json.sessionId || 'default-session';
const userMessage = $json.chatInput || '';
const startedAt = new Date().toISOString();

const normalizedMessage = userMessage
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9 ]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

const cacheKey = normalizedMessage.replace(/\s/g, '_').substring(0, 120);

return {
  chatInput: userMessage,
  sessionId,
  requestId,
  startedAt,
  cacheKey,

  // pass to utility_log_event
  session_id: sessionId,
  request_id: requestId,
  user_message: userMessage,
  status: 'pending',
  selected_agent: '',
  final_response: '',
  duration_ms: 0
};

const initial = $('Prepare Request Context').item.json;
const redisResult = $input.first().json;

return [{
  json: {
    ...initial,
    cachedResponse:
      redisResult.cachedResponse ||
      redisResult.propertyName ||
      redisResult.value ||
      null
  }
}];

const original = $('Merge Cache With Request').item.json;
const logResult = $input.first().json;

let cached = original.cachedResponse;

try {
  if (typeof cached === 'string') {
    cached = JSON.parse(cached);
  }
} catch (error) {
  cached = {
    finalResponse: String(original.cachedResponse || ''),
    selectedAgent: 'cache'
  };
}

if (!cached || typeof cached !== 'object') {
  cached = {
    finalResponse: String(original.cachedResponse || ''),
    selectedAgent: 'cache'
  };
}

const finalResponse =
  cached.finalResponse ||
  cached.final_response ||
  cached.output ||
  '';

const selectedAgent =
  cached.selectedAgent ||
  cached.selected_agent ||
  original.selected_agent ||
  'cache';

const completedAt = new Date().toISOString();
const started = new Date(original.startedAt || original.started_at || Date.now()).getTime();
const durationMs = Date.now() - started;

return [{
  json: {
    ...original,
    ...logResult,
    requestId: original.requestId || original.request_id,
    request_id: original.request_id || original.requestId,
    selectedAgent,
    selected_agent: selectedAgent,
    finalResponse,
    final_response: finalResponse,
    status: 'completed',
    completedAt,
    completed_at: completedAt,
    durationMs,
    duration_ms: durationMs,
    from_cache: true,
    output: finalResponse
  }
}];

const initial = $('Prepare Request Context').item.json;
const agentOutput = String($input.first().json.output || '');

const userMessage = String(
  initial.userMessage ||
  initial.user_message ||
  initial.chatInput ||
  initial.message ||
  ''
);

const text = userMessage
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

let selectedAgent = 'agent_accueil';

// Specific accueil rules must precede "scolarite" and admissions rules.
if (/\b(horaires?\s+d'ouverture|contacts?\s+de\s+la\s+scolarite|contact\s+scolarite|reglement|absences?|inscription\s+administrative|documents?\s+d'inscription)\b/.test(text)) {
  selectedAgent = 'agent_accueil';
} else if (/\b(sql|postgresql|jointures?|joins?|algorithmique|algorithmes?|react\s+native|programmation|codes?|exercices?)\b/.test(text)) {
  selectedAgent = 'agent_pedagogique';
} else if (/\b(pfe|rapport\s+pfe|sujets?\s+pfe|guide\s+pfe|encadrants?\s+pfe|depot\s+du\s+rapport)\b/.test(text)) {
  selectedAgent = 'agent_pfe';
} else if (/\b(plannings?|emplois?\s+du\s+temps|salles?|amphis?|amphitheatres?|examens?|calendriers?|soutenances?|horaires?\s+de\s+cours)\b/.test(text)) {
  selectedAgent = 'agent_planning';
} else if (/\b(formations?|filieres?|diplomes?|admissions?|candidater|candidature|masters?|frais|bourses?|campus|etablissements?|vie\s+etudiante)\b/.test(text)) {
  selectedAgent = 'agent_web';
}

return [{
  json: {
    requestId: initial.requestId || initial.request_id || '',
    sessionId: initial.sessionId || initial.session_id || '',
    userMessage,
    agentResponse: agentOutput,
    selectedAgent
  }
}];

const supervisor = $input.first().json;
const action = supervisor.action || 'accept';
const agentResponse = $('Prepare Supervisor Input').item.json.agentResponse || '';
const improvedResponse = supervisor.improvedResponse || '';
const startedAt = $('Prepare Request Context').item.json.startedAt || '';

let finalResponse = '';
if (action === 'accept') {
  finalResponse = agentResponse;
} else if (action === 'rewrite' && improvedResponse) {
  finalResponse = improvedResponse;
} else if (action === 'human_review') {
  finalResponse = "Je suis désolé, je ne dispose pas d'informations suffisantes pour répondre à cette question. Veuillez contacter l'administration de l'UPF directement.";
} else {
  finalResponse = agentResponse || "Je suis désolé, une erreur est survenue. Veuillez réessayer.";
}

const completedAt = new Date().toISOString();
const durationMs = startedAt ? Math.round(new Date(completedAt) - new Date(startedAt)) : 0;

return [{
  json: {
    output: finalResponse,
    action,
    approved: supervisor.approved,
    score: supervisor.score,
    // analytics fields
    requestId: $('Prepare Request Context').item.json.requestId,
    selectedAgent: $('Prepare Supervisor Input').item.json.selectedAgent || 'unknown',
    finalResponse,
    completedAt,
    durationMs,
    status: 'completed'
  }
}];

let data = $input.first().json;

if (!data.output && data.finalResponse) {
  data.output = data.finalResponse;
}

if (!data.output) {
  try {
    data = $('Prepare Successful DB Update').item.json;
  } catch (error) {
    data = $('Build Cached Response').item.json;
  }
}

return [{
  json: {
    output: data.output || data.finalResponse || data.final_response || ''
  }
}];

const initial = $('Prepare Request Context').item.json;

let selectedAgent = 'unknown';

try {
  const classified = $('Prepare Supervisor Input').item.json;
  selectedAgent =
    classified.selectedAgent ||
    classified.selected_agent ||
    classified.agent ||
    'unknown';
} catch (error) {
  const userMessage = String(
    initial.userMessage ||
    initial.user_message ||
    initial.message ||
    initial.chatInput ||
    ''
  )
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

  if (/\b(sql|postgresql|jointures?|joins?|algorithmique|algorithmes?|react\s+native|programmation|codes?|exercices?)\b/.test(userMessage)) {
    selectedAgent = 'agent_pedagogique';
  } else if (/\b(pfe|rapport\s+pfe|sujets?\s+pfe|guide\s+pfe|encadrants?\s+pfe|depot\s+du\s+rapport)\b/.test(userMessage)) {
    selectedAgent = 'agent_pfe';
  } else if (/\b(plannings?|emplois?\s+du\s+temps|salles?|amphis?|amphitheatres?|examens?|calendriers?|soutenances?|horaires?\s+de\s+cours)\b/.test(userMessage)) {
    selectedAgent = 'agent_planning';
  } else if (/\b(formations?|filieres?|diplomes?|admissions?|candidater|candidature|masters?|frais|scolarite|bourses?|campus|etablissements?|vie\s+etudiante)\b/.test(userMessage)) {
    selectedAgent = 'agent_web';
  } else {
    selectedAgent = 'agent_accueil';
  }
}

return [{
  json: {
    requestId: initial.requestId || initial.request_id || '',
    userMessage: initial.userMessage || initial.user_message || initial.message || initial.chatInput || '',
    selectedAgent,
    output: "Je suis désolé, le service reçoit actuellement trop de demandes ou rencontre une indisponibilité temporaire. Veuillez réessayer dans quelques instants.",
    status: 'failed',
    completedAt: new Date().toISOString()
  }
}];

const result = $('Build Failure Response').item.json;

return [{
  json: {
    output: result.output
  }
}];
